update  swm_post_skill_salary  set grant_flag = 1, frozen_flag = 1
  where grant_flag = 0 and enabled_flag = 1
    and convert(bigint, left(income_period,4) + right(income_period,2))  <= #{updateLimit,jdbcType=BIGINT}


update  swm_post_skill_salary  set frozen_flag = 1
  where frozen_flag = 0 and enabled_flag = 1
        and convert(bigint, left(income_period,4) + right(income_period,2))  <= #{updateLimit,jdbcType=BIGINT}


update swm_post_skill_salary set frozen_flag = 1
where frozen_flag = 0 and enabled_flag = 1
